import{_ as t}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as i,a,o}from"./app-dTHtPceT.js";const s={};function l(n,e){return o(),i("div",null,[...e[0]||(e[0]=[a('<h2 id="classes-and-objects" tabindex="-1"><a class="header-anchor" href="#classes-and-objects"><span>Classes and Objects</span></a></h2><ul><li><p>Class is the blueprint, objects are the instances of their class</p></li><li><p>Class - fields and methods</p><p>Object - properties and behaviors</p></li><li><p>Constructor</p><ul><li>A special method is required to create a new instance of the class</li><li>No return type</li><li>Every objects has a default constructor</li><li>Constructors can be overloaded, using <code>this</code> keyword to overload to avoid duplication</li><li><code>this()</code> must be the first statement in the overloaded constructor body</li><li>If a class doesn&#39;t explicitly declare any constructor, Java compiler automatically provides a no-argument constructor. This default constructor calls the class parent&#39;s no-argument constructor, or the <code>Object</code> constructor if the class has no parent. <strong>If the parent doesn&#39;t have no-argument constructor, compiler will reject the program.</strong></li><li>It&#39;s good to always define a default constructor</li></ul></li><li><p>The <code>getter</code> and <code>setter</code> can also have additional validations instead of just setting or getting the fields values</p></li><li><p>Reference vs. Object</p><ul><li><p>All other types which are not one of the primitive types are reference types</p></li><li><p>References --- pointers</p></li><li><p>The only operators allowed for reference type are assignment via <code>=</code> and equality comparison via <code>==</code> and <code>!=</code> (Strings can use <code>+</code>, <code>+=</code>)</p></li><li><p><code>instance of</code> operator: verify that an particular object is of a certain type</p><ul><li>Typically used before performing a type casting</li></ul></li><li><p><code>new</code> operator instantiates a class by allocating memory for a new object and returning a reference to that memory</p></li><li><p>In Java, there is no way to access an object directly (<em>no pointer</em>), everything is done using a reference</p></li></ul></li><li><p><code>static</code> keyword</p><ul><li>Fields that have <code>static</code> modifier are called static fields or class variables</li><li>They are associated with the class, rather than with any object. Every instance of the class shares a class variable, which is in one fixed location in memory</li><li><code>static</code> methods can&#39;t access instance methods and instance variables directly, and can&#39;t use <code>this</code> keyword</li><li>If a method doesn&#39;t use instance variables that method should be declared as a static method</li><li>Referring to static fields or methods with an object instance is not encouraged</li><li><strong><code>static</code> block</strong>: a code block that will be executed before the creation of any object of that class</li></ul></li><li><p><code>final</code> keyword</p><ul><li><p>Final variables</p><ul><li><p><code>final</code> means a value cannot be changed <strong>after</strong> initialisation at run-time</p><ul><li>Blank finals -&gt; a final field inside a class can be different from each other, and yet it remains its immutablility</li></ul></li><li><p><code>static final</code> means compile-time constant</p></li></ul></li><li><p>Final arguments</p><ul><li>Inside the method you cannot change the argument</li></ul></li><li><p>Final methods</p><ul><li>Prevent the method being overridden by the subclass</li><li>Any private methods in a class are implicitly <code>final</code></li></ul></li><li><p>Final classes</p><ul><li>Prevent the class from being inherited</li></ul></li></ul></li></ul><h2 id="reusing-classes" tabindex="-1"><a class="header-anchor" href="#reusing-classes"><span>Reusing classes</span></a></h2><h3 id="inheritance" tabindex="-1"><a class="header-anchor" href="#inheritance"><span>Inheritance</span></a></h3><ul><li><p><strong>&quot;is-a&quot;</strong> relationship</p></li><li><p><code>extends</code></p></li><li><p>Excepting <code>Object</code>, every class has one and only direct superclass</p></li><li><p>Inheritance chain</p></li><li><p>A subclass inherits all the members (fields, methods, and nested classes) from its super class</p></li><li><p>A subclass doesn&#39;t &quot;inherit&quot; (cannot directly access) the <code>private</code> members of its parent class</p><blockquote><p><a href="https://www.zhihu.com/question/63183685" target="_blank" rel="noopener noreferrer">A great discussion about this topic</a></p></blockquote></li><li><p>Values of the inheritance:</p><ul><li>To handle the complexity of the large project</li><li>Keep common behaviors in one class</li><li>Split different behaviors into separate classes</li><li>Keep all of the objects in a single data structure</li></ul></li><li><p><code>this</code> vs. <code>super</code></p><ul><li><code>super</code> is used to access/call the parent class members</li><li><code>this</code> is used to access/call the current class members</li><li>Both of them can be used anywhere in a class except static areas, any attempt to do so will lead to compile-time errors</li><li><code>this</code> is commonly used with constructors and setters</li><li><code>super</code> is commonly used with method overriding</li><li><code>this()</code> call a constructor from another overloaded constructor in the same class</li><li><code>super()</code> call a parent constructor</li><li><strong>Java compiler puts a default call to <code>super()</code> if we don&#39;t add it</strong>, and it&#39;s always the no-argument <code>super</code> which is inserted by compiler</li><li>A constructor can have a call to <code>super()</code> or <code>this()</code> but never both</li></ul></li><li><p><strong>Method overloading vs. method overriding</strong></p><ul><li><p>Method overloading means providing two or more separate methods in a class with the same name but different parameters</p></li><li><p>We can overload static and instance methods</p></li><li><p>Overloading rules</p><ul><li>Methods must have the same method name</li><li>Methods must have different parameters</li><li>If methods follow the rules above then they may or may ont <ul><li>Have different return types</li><li>Have different access modifiers</li><li>Throw different checked or unchecked exceptions</li></ul></li></ul></li><li><p>Method overriding means defining a method in a child class that already exists in the parent class with same signature</p></li><li><p>Overriding rules</p><ul><li><p>It must have same name and same arguments</p></li><li><p>Return type can be a subclass of the return type in the parent class</p><blockquote><p>Covariant return types</p></blockquote></li><li><p>We can&#39;t override static methods only instance methods</p></li><li><p>Constructors and private methods cannot be overridden</p></li><li><p>Methods that are final cannot be overridden</p></li><li><p>It can&#39;t have a lower access modifier</p></li><li><p>Must not throw a new or broader checked exception</p></li></ul></li></ul></li></ul><h3 id="composition" tabindex="-1"><a class="header-anchor" href="#composition"><span>Composition</span></a></h3><ul><li><strong>&quot;has-a&quot;</strong> relationship</li><li>Use class type variables as fields</li><li>Consider to use composition prior to inheritance</li></ul><h2 id="encapsulation" tabindex="-1"><a class="header-anchor" href="#encapsulation"><span>Encapsulation</span></a></h2><ul><li>Separate the implementation and the interface</li></ul><h2 id="polymorphism" tabindex="-1"><a class="header-anchor" href="#polymorphism"><span>Polymorphism</span></a></h2><ul><li>Compile Time Rules <ul><li>Compiler <strong>ONLY</strong> knows reference type</li><li>Can only look in reference type class for method</li><li>Outputs a method signature</li></ul></li><li>Runtime Rules <ul><li>Follow exact <strong>runtime type</strong> of object to find the method</li><li>Must match compile time method signature to appropriate method in actual object&#39;s class</li></ul></li></ul>',11)])])}const d=t(s,[["render",l]]),p=JSON.parse(`{"path":"/notes/language/java/oop.html","title":"OOP","lang":"en-US","frontmatter":{"title":"OOP","category":["Note"],"tag":["Language","Java"],"footer":false,"editLink":false,"description":"Classes and Objects Class is the blueprint, objects are the instances of their class Class - fields and methods Object - properties and behaviors Constructor A special method is...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"OOP\\",\\"image\\":[\\"\\"],\\"dateModified\\":null,\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Hadjshell\\",\\"url\\":\\"https://github.com/hadjShell\\"}]}"],["meta",{"property":"og:url","content":"https://hadjshell.netlify.app/notes/language/java/oop.html"}],["meta",{"property":"og:site_name","content":"Hadjshell's Field"}],["meta",{"property":"og:title","content":"OOP"}],["meta",{"property":"og:description","content":"Classes and Objects Class is the blueprint, objects are the instances of their class Class - fields and methods Object - properties and behaviors Constructor A special method is..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"article:tag","content":"Java"}],["meta",{"property":"article:tag","content":"Language"}]]},"git":{},"readingTime":{"minutes":2.92,"words":877},"filePathRelative":"notes/language/java/oop.md","excerpt":"","autoDesc":true}`);export{d as comp,p as data};
